                        { label: 'Employee Directory', icon: <Users size={14} className="text-[#003a8c]" />, bg: 'bg-[#ebf5ff]' },
                        { label: 'Leave Approvals', icon: <CalendarClock size={14} className="text-[#d4380d]" />, bg: 'bg-[#fdf8f5]' },
