                          </div>
                          <span className="text-xs font-semibold text-slate-700 leading-tight pr-1 group-hover:text-slate-900 transition-colors flex-1">{link.label}</span>
                          <ChevronRight size={14} className="text-slate-300 group-hover:text-slate-500 group-hover:translate-x-0.5 transition-all mr-1" />
                        </div>
                      ))}
                    </div>
                  </div>
                </CardContent>
              </Card>


              </div>
            </div>

            {/* Right Column (Sidebar) */}
            <div className={`space-y-3 ${activeNav === 'dashboard2' ? 'order-first' : 'order-last'}`}>

              {/* BlueTree Logo Card */}
              <Card className="border-slate-200 shadow-md flex items-center justify-center p-6 bg-white">
                <img src={blueTreeLogo} alt="BlueTree" className="h-14 md:h-16 w-auto object-contain" />
              </Card>

              {/* Actions Section (Updated) */}
              <Card className="border-brand/20 shadow-md">
                <CardHeader className="flex flex-row items-center justify-between px-4 py-3 bg-slate-50/50 rounded-t-xl border-b space-y-0">
                  <CardTitle className="text-lg font-bold text-slate-800">Needs Attention</CardTitle>
                  <div className="flex items-center gap-1.5 p-1 bg-white border shadow-sm rounded-full w-fit">
                    {[
                      { id: 'All', icon: <Grid size={14} />, tooltip: 'All Modules' },
                      { id: 'Core', icon: <Fingerprint size={14} />, tooltip: 'Core' },
                      { id: 'Time & Attendance', icon: <CalendarClock size={14} />, tooltip: 'Time & Attendance' },
                      { id: 'Onboarding', icon: <Handshake size={14} />, tooltip: 'Onboarding' },
                      { id: 'Compliance', icon: <Landmark size={14} />, tooltip: 'Compliance' },
                      { id: 'Payout', icon: <ReceiptText size={14} />, tooltip: 'Payout' },
                      { id: 'Offboarding', icon: <UserMinus size={14} />, tooltip: 'Offboarding' },
                      { id: 'Grievances', icon: <Headset size={14} />, tooltip: 'Grievances (Help Desk)' }
                    ].map(mod => (
                      <button
                        key={mod.id}
                        onClick={() => setSelectedModuleFilter(mod.id)}
                        className={`group relative w-7 h-7 rounded-full flex items-center justify-center transition-all ${selectedModuleFilter === mod.id ? 'bg-[#0056c1] text-white shadow-md' : 'text-slate-500 hover:bg-slate-100 hover:text-slate-800'}`}
                      >
                        {mod.icon}
                        <span className="absolute -top-8 left-1/2 -translate-x-1/2 whitespace-nowrap rounded bg-slate-900 px-2 py-1 text-[10px] font-medium text-white shadow-sm opacity-0 transition-opacity group-hover:opacity-100 pointer-events-none z-50">
                              {mod.tooltip}
                        </span>
                      </button>
                    ))}
                  </div>
                </CardHeader>
                <CardContent className="p-0">
                  {activeNav === 'dashboard2' ? (
                    <div className="flex flex-col">
                      {dashboard2NeedsAttention.map(item => (
                        <div key={item.id} className="flex items-center justify-between p-4 border-b hover:bg-slate-50 transition-colors cursor-pointer group">
                          <div className="flex items-center gap-4">
                            <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 ${item.iconBg}`}>
                              {item.icon}
                            </div>
                            <div className="flex flex-col">
                              <span className="text-sm font-semibold text-slate-800">{item.title}</span>
                              <div className="flex items-center gap-1.5 mt-0.5 text-xs text-slate-500">
                                <span>{item.subtitle}</span>
                              </div>
                            </div>
                          </div>
                          <div className="flex items-center gap-3">
                            <span className={`text-[10px] font-bold px-2.5 py-1 rounded-full ${
                                  item.color === 'red' ? 'text-red-700 bg-red-100' : 
                                  item.color === 'orange' ? 'text-amber-700 bg-amber-100' : 
                                  item.color === 'purple' ? 'text-purple-700 bg-purple-100' : 
                                  'text-blue-700 bg-blue-100'
                                }`}>
                              {item.count} pending
                            </span>
                            <ChevronRight size={16} className="text-slate-400 group-hover:text-slate-600" />
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (() => {
                    const allActions = [
                      ...actions['due-today'].map(a => ({...a, category: 'due-today'})),
                      ...actions['needs-action'].map(a => ({...a, category: 'needs-action'})),
                      ...actions['overdue'].map(a => ({...a, category: 'overdue'}))
                    ].filter(a => selectedModuleFilter === 'All' || a.module === selectedModuleFilter);

                    const isExpanded = expandedTabs['all'];
                    
                    if (allActions.length === 0) {
                      return (
                        <div className="p-8 text-center flex flex-col items-center justify-center text-slate-500 min-h-[200px]">
                          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4">
                            <CheckCircle2 size={32} className="text-slate-300" />
                          </div>
                          <h4 className="text-sm font-semibold text-slate-700 mb-1">All caught up!</h4>
                          <p className="text-xs">No tasks requiring action.</p>
                        </div>
                      );
                    }

                    const visibleActions = isExpanded ? allActions : allActions.slice(0, 4);

                    return (
                      <div className="flex flex-col">
                        {visibleActions.map(action => (
                          <div key={action.id} className="flex flex-col p-4 border-b hover:bg-slate-50 transition-colors group gap-3">
                            <div className="flex gap-3">
                              <div className={`w-10 h-10 rounded-md flex items-center justify-center shrink-0 ${
                                action.category === 'overdue' ? 'bg-red-100 text-red-600' :
                                action.category === 'needs-action' ? 'bg-orange-100 text-orange-600' :
                                'bg-blue-100 text-brand'
                              }`}>
                                {action.type === 'timesheet' && <Clock size={20} />}
                                {action.type === 'compliance' && <FileText size={20} />}
                                {(action.type !== 'timesheet' && action.type !== 'compliance') && <CheckCircle2 size={20} />}
                              </div>
                              
                              <div className="flex-1 min-w-0 flex flex-col">
                                <div className="flex justify-between items-start mb-1">
                                  <p className="text-sm text-slate-800 leading-snug pr-2">
                                    {action.desc}
                                  </p>
                                </div>
                                <div className="flex items-center gap-2">
                                  <span className="text-xs text-slate-400">{action.module}</span>
                                </div>
                              </div>
                            </div>
                            
                            <div className="flex items-center justify-between w-full mt-1">
                                <span className={`text-[10px] font-bold px-2 py-0.5 rounded flex items-center gap-1 uppercase tracking-wider ${
                                  action.tagColor === 'red' ? 'text-red-600 bg-red-50' : 
                                  action.tagColor === 'orange' ? 'text-orange-600 bg-orange-50' : 
                                  'text-blue-600 bg-blue-50'
                                }`}>
                                  {action.tag}
                                </span>
                                <div className="flex gap-2">
                                  <Button size="sm" variant="outline" className="h-8 text-xs px-3 shadow-sm border-slate-200 font-medium" onClick={() => openDetails(action as any)}>View Details</Button>
                                </div>
                            </div>
                          </div>
                        ))}
                        {allActions.length > 4 && (
                          <div className="p-3 text-center bg-white border-t">
                            <button 
                              onClick={() => setExpandedTabs(prev => ({ ...prev, all: !prev.all }))}
                              className="text-xs font-semibold text-[#0056c1] hover:underline uppercase tracking-wide"
                            >
                              {isExpanded ? 'Show Less' : `View All Actions (${allActions.length})`}
                            </button>
                          </div>
                        )}
                      </div>
                    );
                  })()}
                </CardContent>
              </Card>
            </div>
          </div>
        </ScrollArea>

      </main>

      {/* Task Details Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              Task Details
              <Badge variant="outline" className="ml-2 font-normal text-xs">{selectedAction?.module}</Badge>
            </DialogTitle>
            <DialogDescription>
              Review the information below before taking action.
            </DialogDescription>
          </DialogHeader>
          
          {selectedAction && (
            <div className="py-4 space-y-4">
              <div className="space-y-1">
                <h4 className="text-sm font-medium text-slate-500">Task</h4>
                <p className="text-sm text-slate-900 font-medium">{selectedAction.desc}</p>
              </div>
              
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <h4 className="text-sm font-medium text-slate-500">Employee</h4>
                  <p className="text-sm text-slate-900">{selectedAction.employeeName}</p>
                </div>
                <div className="space-y-1">
                  <h4 className="text-sm font-medium text-slate-500">Priority Tag</h4>
                  <div className="mt-1">
                    <span className={`text-xs font-bold px-2 py-1 rounded flex items-center w-fit gap-1 uppercase tracking-wider ${
                      selectedAction.tagColor === 'red' ? 'text-red-600 bg-red-50' : 
                      selectedAction.tagColor === 'orange' ? 'text-orange-600 bg-orange-50' : 
                      'text-blue-600 bg-blue-50'
                    }`}>
                      {selectedAction.tag}
                    </span>
                  </div>
                </div>
              </div>

              <div className="space-y-1 bg-slate-50 p-3 rounded-md border border-slate-100">
                <h4 className="text-sm font-medium text-slate-500">Notes</h4>
                <p className="text-sm text-slate-700">{selectedAction.notes}</p>
              </div>
            </div>
          )}

          <DialogFooter className="flex items-center gap-2 sm:justify-end">
            <Button variant="outline" onClick={() => setIsModalOpen(false)}>Cancel</Button>
            {selectedAction && (
              <Button 
                onClick={() => handleApprove(getActionTabKey(selectedAction.id), selectedAction.id)}
                className="bg-brand hover:bg-brand/90"
              >
                Approve
              </Button>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';
import useMeasure from 'react-use-measure';
import { AnimatePresence, motion, MotionConfig } from 'motion/react';
import { cn } from '@/lib/utils';
import useClickOutside from '@/hooks/useClickOutside';
import { Megaphone, X } from 'lucide-react';

const transition: any = {
  type: 'spring',
  bounce: 0.1,
  duration: 0.25,
};

export default function AnnouncementMic({ position = 'left' }: { position?: 'left' | 'right' }) {
  const [active, setActive] = useState<number | null>(null);
  const [contentRef, { height: heightContent }] = useMeasure();
  const [menuRef, { width: widthContainer }] = useMeasure();
  const ref = useRef<HTMLDivElement>(null);
  const [isOpen, setIsOpen] = useState(false);
  const [maxWidth, setMaxWidth] = useState(0);

  useClickOutside(ref, () => {
    setIsOpen(false);
    setActive(null);
  });

  useEffect(() => {
    if (!widthContainer || maxWidth > 0) return;
    setMaxWidth(widthContainer);
  }, [widthContainer, maxWidth]);

  return (
    <MotionConfig transition={transition}>
      <div className={`absolute top-0 z-50 ${position === 'left' ? '-left-14 xl:-left-16' : '-right-14 xl:-right-16'}`} ref={ref}>
        <div className='h-full w-full rounded-2xl border border-slate-200 bg-white shadow-lg overflow-hidden'>
          <div className={`flex space-x-2 p-1.5 ${position === 'right' ? 'justify-end' : ''}`} ref={menuRef}>
            <button
              aria-label="Announcements"
              className={cn(
                'relative flex h-11 w-11 shrink-0 scale-100 select-none appearance-none items-center justify-center rounded-xl text-slate-500 transition-all hover:bg-slate-100 hover:text-brand focus-visible:ring-2 active:scale-[0.98]',
                active === 1 ? 'bg-blue-50 text-brand' : ''
              )}
              type='button'
              onClick={() => {
                if (!isOpen) {
                  setIsOpen(true);
                  setActive(1);
                } else {
                  setIsOpen(false);
                  setActive(null);
                }
              }}
            >
              <Megaphone className='h-5 w-5' />
              {!isOpen && <span className="absolute top-2.5 right-2.5 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white"></span>}
            </button>
          </div>
          <div className='overflow-hidden'>
            <AnimatePresence initial={false} mode='sync'>
              {isOpen ? (
                <motion.div
                  key='content'
                  initial={{ height: 0 }}
                  animate={{ height: heightContent || 0 }}
                  exit={{ height: 0 }}
                  style={{ width: maxWidth > 320 ? maxWidth : 320 }}
                >
                  <div ref={contentRef} className='p-4 pt-2'>
                    <div className="flex justify-between items-center mb-4 border-b pb-2">
                      <h4 className="font-bold text-slate-800 flex items-center gap-2">
                        <Megaphone size={16} className="text-brand" />
                        Announcements
                      </h4>
                      <button 
                        onClick={() => { setIsOpen(false); setActive(null); }}
                        className="text-slate-400 hover:text-slate-700 rounded-full hover:bg-slate-100 p-1 transition-colors"
                      >
                        <X size={16} />
                      </button>
                    </div>
                    <div className="space-y-3">
                      <div className="p-3 bg-blue-50/80 text-blue-900 rounded-lg text-sm border border-blue-100/50 hover:bg-blue-50 transition-colors cursor-pointer">
                        <strong className="block mb-1 text-blue-950">Company Townhall</strong>
                        Join us this Friday at 3 PM for the Q3 Company Townhall meeting.
                      </div>
                      <div className="p-3 bg-amber-50/80 text-amber-900 rounded-lg text-sm border border-amber-100/50 hover:bg-amber-50 transition-colors cursor-pointer">
                        <strong className="block mb-1 text-amber-950">Payroll Update</strong>
                        Payroll module will be down for maintenance this weekend.
                      </div>
                    </div>
                  </div>
                </motion.div>
              ) : null}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </MotionConfig>
  );
}
